from __future__ import annotations

import base64
import json
import py_compile
import shutil
import time
from pathlib import Path

PATCH_ID = "4B436633E"
PATCH_VERSION = "4B.4.3.6.6.33E"
PATCH_NAME = "Status Conflict Resolver"
PAYLOAD = {
  "README_APPLY_4B436633E.txt": "",
  "docs/STATUS_CONFLICT_RESOLVER_4B436633E.md": "",
  "src/tradebot/status_conflict_resolver.py": "",
  "tests/test_status_conflict_resolver_4B436633E.py": "",
  "tools/check_4B436633E_status_conflict_resolver.py": "",
  "tools/run_4B436633E_status_conflict_resolver.py": ""
}


def _repo_root() -> Path:
    return Path(__file__).resolve().parents[1]


def _backup_existing(root: Path, rel_path: str, backup_root: Path, backed_up: list[str]) -> None:
    target = root / rel_path
    if not target.exists():
        return
    backup_path = backup_root / rel_path
    backup_path.parent.mkdir(parents=True, exist_ok=True)
    shutil.copy2(target, backup_path)
    backed_up.append(rel_path)


def main() -> int:
    root = _repo_root()
    backup_root = root / "tools" / f"_patch_backup_{PATCH_ID}_{time.strftime('%Y%m%dT%H%M%SZ', time.gmtime())}"
    backed_up: list[str] = []
    written: list[str] = []
    for rel_path, encoded in PAYLOAD.items():
        _backup_existing(root, rel_path, backup_root, backed_up)
        target = root / rel_path
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(base64.b64decode(encoded).decode("utf-8"), encoding="utf-8")
        written.append(rel_path)

    compile_errors: dict[str, str] = {}
    for rel_path in written:
        if rel_path.endswith(".py"):
            try:
                py_compile.compile(str(root / rel_path), doraise=True)
            except Exception as exc:
                compile_errors[rel_path] = f"{type(exc).__name__}: {exc}"

    payload = {
        "applied": not compile_errors,
        "patch_id": PATCH_ID,
        "patch_version": PATCH_VERSION,
        "patch_name": PATCH_NAME,
        "written_files": written,
        "backed_up_files": backed_up,
        "backup_root": str(backup_root.relative_to(root)) if backed_up else "",
        "compile_errors": compile_errors,
        "py_compile_ok": not compile_errors,
        "approved_for_live_real": False,
        "approved_for_paper_transition": False,
        "approved_for_exchange_submit": False,
        "approved_for_runtime_overlay": False,
        "trading_action_performed": False,
        "training_performed": False,
        "reload_performed": False,
        "exchange_submit_performed": False,
        "runtime_overlay_activated": False,
        "destructive_cleanup_performed": False,
    }
    print(json.dumps(payload, indent=2, sort_keys=True))
    return 0 if not compile_errors else 1


if __name__ == "__main__":
    raise SystemExit(main())
